<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Maze Bots — 24 Autonomous Pathfinders</title>
<style>
  :root{
    --bg:#0d1117; --panel:#161b22; --wall:#58a6ff; --floor:#0d1117;
    --accent:#3fb950; --text:#e6edf3; --muted:#8b949e; --spawn:#f778ba; --exit:#3fb950;
  }
  *{box-sizing:border-box}
  html,body{margin:0;height:100%}
  body{
    background:radial-gradient(1200px 600px at 50% -10%,#12203a,var(--bg));
    color:var(--text);
    font-family:"Segoe UI",system-ui,-apple-system,Roboto,Helvetica,Arial,sans-serif;
    display:flex;flex-direction:column;align-items:center;
    min-height:100%;padding:24px 16px 40px;gap:18px;
  }
  h1{
    font-size:22px;font-weight:700;margin:0;letter-spacing:.3px;
    background:linear-gradient(90deg,#58a6ff,#3fb950,#f778ba);
    -webkit-background-clip:text;background-clip:text;color:transparent;
  }
  .sub{color:var(--muted);font-size:13px;margin-top:-10px}
  #hud{
    display:flex;flex-wrap:wrap;gap:12px;justify-content:center;align-items:center;
  }
  .card{
    background:var(--panel);border:1px solid #21262d;border-radius:12px;
    padding:10px 16px;min-width:120px;text-align:center;
    box-shadow:0 4px 18px rgba(0,0,0,.35);
  }
  .card .label{font-size:11px;text-transform:uppercase;letter-spacing:1px;color:var(--muted)}
  .card .value{font-size:20px;font-weight:700;margin-top:2px}
  #completed .value,#completed{color:var(--accent)}
  #reset{
    cursor:pointer;border:none;border-radius:12px;padding:12px 22px;
    font-size:15px;font-weight:700;color:#04140a;
    background:linear-gradient(180deg,#4ae168,#2ea043);
    box-shadow:0 4px 14px rgba(46,160,67,.45);transition:transform .08s,filter .15s;
  }
  #reset:hover{filter:brightness(1.08)}
  #reset:active{transform:translateY(1px) scale(.98)}
  .stage{
    background:var(--panel);border:1px solid #21262d;border-radius:16px;
    padding:14px;box-shadow:0 10px 40px rgba(0,0,0,.5);
  }
  #maze{
    display:block;border-radius:8px;background:var(--floor);
    image-rendering:auto;
  }
  .progress{
    width:100%;max-width:452px;height:8px;background:#21262d;border-radius:6px;overflow:hidden;
  }
  .progress>i{display:block;height:100%;width:0;background:linear-gradient(90deg,#3fb950,#58a6ff);transition:width .2s}
</style>
</head>
<body>
  <h1>Maze Bots</h1>
  <div class="sub">24 autonomous pathfinders racing a perfect maze to the exit</div>

  <div id="hud">
    <div class="card"><div class="label">Completed</div><div id="completed" class="value">0 / 24</div></div>
    <div class="card"><div class="label">Elapsed</div><div id="timer" class="value">0.0s</div></div>
    <div class="card"><div class="label">Active</div><div id="active" class="value">24</div></div>
    <button id="reset">↻ Reset</button>
  </div>

  <div class="progress"><i id="bar"></i></div>

  <div class="stage">
    <canvas id="maze" width="422" height="422"></canvas>
  </div>

<script>
(function(){
  "use strict";

  // ---- Configuration -------------------------------------------------------
  const COLS = 21, ROWS = 21;          // >= 15x15
  const CELL = 20;                     // px per cell -> 21*20 = 420 (>=400)
  const WALL = 2;                      // wall line thickness
  const N_BOTS = 24;
  const SPAWN = {x:0, y:0};
  const EXIT  = {x:COLS-1, y:ROWS-1};
  const SPAWN_INTERVAL = 3;            // steps between successive bot launches (anti-blob)
  const STEP_MS = 60;                  // logical ms represented by one step
  const LIVE_STEP_MS = 60;             // real ms between live steps

  const canvas = document.getElementById('maze');
  const ctx = canvas.getContext('2d');
  canvas.width  = COLS*CELL + WALL;
  canvas.height = ROWS*CELL + WALL;

  const elCompleted = document.getElementById('completed');
  const elTimer     = document.getElementById('timer');
  const elActive    = document.getElementById('active');
  const elBar       = document.getElementById('bar');
  const elReset     = document.getElementById('reset');

  // ---- Maze generation (recursive backtracker -> perfect maze) -------------
  const DIRS = [['N',0,-1],['S',0,1],['E',1,0],['W',-1,0]];
  const OPP  = {N:'S',S:'N',E:'W',W:'E'};

  function genMaze(){
    const cells = [];
    for(let y=0;y<ROWS;y++){
      const row=[];
      for(let x=0;x<COLS;x++) row.push({N:true,E:true,S:true,W:true,visited:false});
      cells.push(row);
    }
    const stack=[[SPAWN.x,SPAWN.y]];
    cells[SPAWN.y][SPAWN.x].visited=true;
    while(stack.length){
      const [x,y]=stack[stack.length-1];
      const nb=[];
      for(const [d,dx,dy] of DIRS){
        const nx=x+dx, ny=y+dy;
        if(nx>=0&&nx<COLS&&ny>=0&&ny<ROWS&&!cells[ny][nx].visited) nb.push([d,nx,ny]);
      }
      if(nb.length){
        const [d,nx,ny]=nb[(Math.random()*nb.length)|0];
        cells[y][x][d]=false;
        cells[ny][nx][OPP[d]]=false;
        cells[ny][nx].visited=true;
        stack.push([nx,ny]);
      } else stack.pop();
    }
    return cells;
  }

  // ---- BFS shortest path (guaranteed to exist in a perfect maze) -----------
  function bfs(cells, sx,sy, ex,ey){
    const prev = Array.from({length:ROWS},()=>Array(COLS).fill(null));
    const seen = Array.from({length:ROWS},()=>Array(COLS).fill(false));
    const q=[[sx,sy]]; seen[sy][sx]=true;
    while(q.length){
      const [x,y]=q.shift();
      if(x===ex&&y===ey) break;
      for(const [d,dx,dy] of DIRS){
        if(cells[y][x][d]) continue;            // wall blocks
        const nx=x+dx, ny=y+dy;
        if(nx<0||nx>=COLS||ny<0||ny>=ROWS||seen[ny][nx]) continue;
        seen[ny][nx]=true; prev[ny][nx]=[x,y]; q.push([nx,ny]);
      }
    }
    const path=[]; let c=[ex,ey];
    while(c){ path.push({x:c[0],y:c[1]}); c=prev[c[1]][c[0]]; }
    path.reverse();
    return path;
  }

  // ---- Game state ----------------------------------------------------------
  let cells, basePath, bots, completedCount, stepCount, elapsedMs;

  function makeBots(){
    const arr=[];
    for(let i=0;i<N_BOTS;i++){
      arr.push({
        id:i,
        x:SPAWN.x, y:SPAWN.y,
        path:basePath,
        pathIndex:0,
        startStep:i*SPAWN_INTERVAL,
        finished:false,
        hue:(i*360/N_BOTS)|0,
        // fixed in-cell jitter so overlapping bots stay visually distinct
        jx:((i*53)%100)/100*0.5 - 0.25,
        jy:((i*97)%100)/100*0.5 - 0.25,
      });
    }
    return arr;
  }

  function build(){
    cells    = genMaze();
    basePath = bfs(cells, SPAWN.x,SPAWN.y, EXIT.x,EXIT.y);
    bots     = makeBots();
    completedCount = 0;
    stepCount = 0;
    elapsedMs = 0;
  }

  // Advance the whole simulation by exactly one step.
  function step(){
    if(completedCount >= N_BOTS) return;        // done -> time frozen
    for(const b of bots){
      if(b.finished) continue;
      if(stepCount < b.startStep) continue;     // still waiting to launch
      if(b.pathIndex < b.path.length-1){
        b.pathIndex++;
        b.x = b.path[b.pathIndex].x;
        b.y = b.path[b.pathIndex].y;
      }
      if(b.pathIndex >= b.path.length-1){
        b.finished = true;
        completedCount++;
      }
    }
    stepCount++;
    elapsedMs += STEP_MS;
  }

  // ---- Rendering -----------------------------------------------------------
  function drawWallLine(x1,y1,x2,y2){
    ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(x2,y2); ctx.stroke();
  }

  function render(){
    ctx.clearRect(0,0,canvas.width,canvas.height);

    // spawn & exit cells
    ctx.fillStyle='rgba(247,120,186,.22)';
    ctx.fillRect(SPAWN.x*CELL+WALL/2, SPAWN.y*CELL+WALL/2, CELL, CELL);
    ctx.fillStyle='rgba(63,185,80,.28)';
    ctx.fillRect(EXIT.x*CELL+WALL/2, EXIT.y*CELL+WALL/2, CELL, CELL);

    // exit glow marker
    ctx.fillStyle='#3fb950';
    ctx.font='bold 12px system-ui';
    ctx.textAlign='center'; ctx.textBaseline='middle';
    ctx.fillText('◎', EXIT.x*CELL+WALL/2+CELL/2, EXIT.y*CELL+WALL/2+CELL/2);
    ctx.fillStyle='#f778ba';
    ctx.fillText('◉', SPAWN.x*CELL+WALL/2+CELL/2, SPAWN.y*CELL+WALL/2+CELL/2);

    // walls
    ctx.strokeStyle=getComputedStyle(document.documentElement).getPropertyValue('--wall').trim()||'#58a6ff';
    ctx.lineWidth=WALL; ctx.lineCap='round';
    const o=WALL/2;
    for(let y=0;y<ROWS;y++){
      for(let x=0;x<COLS;x++){
        const c=cells[y][x];
        const px=x*CELL+o, py=y*CELL+o;
        if(c.N) drawWallLine(px,py,px+CELL,py);
        if(c.W) drawWallLine(px,py,px,py+CELL);
        if(c.E) drawWallLine(px+CELL,py,px+CELL,py+CELL);
        if(c.S) drawWallLine(px,py+CELL,px+CELL,py+CELL);
      }
    }

    // bots
    const r=CELL*0.30;
    for(const b of bots){
      const cx=b.x*CELL+WALL/2 + CELL/2 + b.jx*CELL;
      const cy=b.y*CELL+WALL/2 + CELL/2 + b.jy*CELL;
      ctx.beginPath();
      ctx.arc(cx,cy,r,0,Math.PI*2);
      if(b.finished){
        ctx.fillStyle=`hsl(${b.hue},70%,55%)`;
        ctx.globalAlpha=0.45;
      } else {
        ctx.fillStyle=`hsl(${b.hue},85%,60%)`;
        ctx.globalAlpha=1;
      }
      ctx.fill();
      ctx.globalAlpha=1;
      ctx.lineWidth=1.2;
      ctx.strokeStyle='rgba(255,255,255,.75)';
      ctx.stroke();
    }
  }

  function updateHUD(){
    elCompleted.textContent = completedCount + ' / ' + N_BOTS;
    elTimer.textContent = (elapsedMs/1000).toFixed(1) + 's';
    elActive.textContent = (N_BOTS - completedCount);
    elBar.style.width = (completedCount/N_BOTS*100).toFixed(1) + '%';
  }

  // ---- Live animation loop (real-time play) --------------------------------
  let lastTime = null, acc = 0, rafId = null;
  function loop(t){
    if(lastTime===null) lastTime=t;
    let dt=t-lastTime; lastTime=t;
    if(dt>500) dt=500;                 // clamp after tab-away
    acc += dt;
    while(acc>=LIVE_STEP_MS && completedCount<N_BOTS){
      step(); acc-=LIVE_STEP_MS;
    }
    render(); updateHUD();
    rafId=requestAnimationFrame(loop);
  }
  function startLoop(){
    if(rafId!==null) cancelAnimationFrame(rafId);
    lastTime=null; acc=0;
    rafId=requestAnimationFrame(loop);
  }

  // ---- Public API for automated grading ------------------------------------
  function reset(){
    build();
    render(); updateHUD();
    startLoop();
  }

  const game = {
    get bots(){ return bots; },
    get completed(){ return completedCount; },
    get elapsedMs(){ return elapsedMs; },
    tick(n){
      n = (n|0);
      for(let i=0;i<n;i++) step();
      render(); updateHUD();
      return completedCount;
    },
    reset(){ reset(); }
  };
  window.game = game;

  // ---- Wire up controls & boot --------------------------------------------
  elReset.addEventListener('click', reset);

  build();
  render(); updateHUD();
  startLoop();
})();
</script>
</body>
</html>
